%[text] # Week 5
%[text] ## Function with no inputs, no outputs
% Call the function, this is the main script
noInputsNoOutputs();

% This is function
function noInputsNoOutputs()
    disp('This function has no inputs and no outputs.');
end %[output:9335104e]
%%
%[text] ## Function with no inputs, but with outputs
% Call the function, this is the main script
[a, b, c] = noInputsHaveOutputs();
disp(['a: ', num2str(a), ', b: ', num2str(b), ', c: ', num2str(c)]);

% This is function
function [a, b, c] = noInputsHaveOutputs()
    a = 1;
    b = 2;
    c = 3;
end %[output:9fd9cb1b]
%%
%[text] ## Function with inputs and no outputs
% Call the function, this is the main script
haveInputsNoOutputs(10, 20, 30);

% This is function
function haveInputsNoOutputs(x, y, z)
    disp(['x: ', num2str(x), ', y: ', num2str(y), ', z: ', num2str(z)]);
end %[output:6a612473]
%%
%[text] ## Function with inputs and outputs
% Call the function, this is the main script
[aSum, aProduct] = haveInputsHaveOutputs(5, 7);
disp(['Sum: ', num2str(aSum), ', Product: ', num2str(aProduct)]);

% This is function
function [sum, product] = haveInputsHaveOutputs(a, b)
    sum = a + b;
    product = a * b;
end %[output:25885274]
%%
%[text] ## Variables passing with different names and orders
% Call the function, this is the main script
a = 10;
b = 20;
c = 30;
[z, x, y] = exampleFunction(c, a, b);
disp(['x: ', num2str(x), ', y: ', num2str(y), ', z: ', num2str(z)]);

% This is function
function [x, y, z] = exampleFunction(a, b, c)
    % Perform some operations
    x = a + 1;
    y = b + 1;
    z = c + 1;
end %[output:65621348]
%[text] In this example:
%[text] - The main script defines variables a, b, and c.
%[text] - These variables are passed to the function exampleFunction in the order c, a, b.
%[text] - Inside the function, they are received as a, b, and c respectively.
%[text] - The function performs operations and returns the results as x, y, and z.
%[text] - The main script receives the results in the order z, x, y and displays them. \
%%
%[text] ## Example on variable values not passed out
% Main script
a = 10;
b = 20;
c = 30;
exampleFunction2(a, b, c);
disp(['Main script - a: ', num2str(a), ', b: ', num2str(b), ', c: ', num2str(c)]);

% This is function
function exampleFunction2(a, b, c)
    % Modify the variables
    a = a + 1;
    b = b + 1;
    c = c + 1;
    % Display the values of a, b, and c inside the function
    disp(['Function - a: ', num2str(a), ', b: ', num2str(b), ', c: ', num2str(c)]);
end %[output:144737ea] %[output:129ad7e9]
%%
%[text] ## Examples of multiple functions in a .m file
% This is one .m file

[p1, p2] = get_values; % calling function_1 to get p1, p2 %[output:82f30226]
choice = user_menu;    % calling function_2 to get choice %[output:0fc3f7c8]
% Switch case to call the appropriate function
switch choice %[output:group:488e45de]
    case 1
        % Calculate acceleration, p1 goes to F, p2 goes to m
        F = p1;
        m = p2;
        a = calculateAcceleration(F, m);
        disp(['The acceleration is: ', num2str(a)]);
    case 2
        % Calculate mass, p1 goes to F, p2 goes to a
        F = p1;
        a = p2;
        m = calculateMass(F, a);
        disp(['The mass is: ', num2str(m)]);
    case 3
        % Calculate force, p1 goes to m, p2 goes to a
        m = p1;
        a = p2;
        F = calculateForce(m, a);
        disp(['The force is: ', num2str(F)]); %[output:4ec25064]
    otherwise
        disp('Invalid choice');
end
% main script ends here %[output:group:488e45de]
function [p1, p2] = get_values
    % Take input from the user
    disp('Please enter two parameters in the order of F, m, a')
    p1 = input('Enter the first parameter: ');
    p2 = input('Enter the second parameter: ');
end

function choice = user_menu
    % Display the menu
    disp('1. Calculate acceleration');
    disp('2. Calculate mass');
    disp('3. Calculate force');
    % Take input from the user
    choice = input('Enter your choice: ');
end

function a = calculateAcceleration(F, m)
    a = F/m;
end

function m = calculateMass(F, a)
    m = F/a;
end

function F = calculateForce(m, a)
    F = m*a;
end
%%
%[text] ## Review on solving linear equations
fileName = 'None'; % a random name for the file

% Indefinite check until the file exists
while exist(fileName, 'file') == 0
    fileName = input('Enter the name of the data file: ', 's');
end

% Load the data from the file
data = load(fileName);

% Get the size of the data matrix and 
% Check if the data matrix has the correct dimensions
[m, n] = size(data);
if n ~= m + 1
    disp('The data matrix must have n columns and n-1 rows.');
    return;
end

% Separate matrix A and vector b
A = data(:, 1:end-1);
b = data(:, end);

% Check if the determinant of A is non-zero
if det(A) == 0
    disp('Matrix A is singular and cannot be inverted.');
    return;
end

% Solve for X
X = inv(A) * b;
% Display the solution
disp('The solution vector X is:'); %[output:7d2153c1]
disp(X); %[output:6c47f86d]
%%
%[text] ## Plot vectors x and y
% Define the vectors x and y
x = 0:0.1:10;
y1 = 20:0.2:40;

%Create a plot of x and y
figure(1); %[output:9ba11935]
plot(x, y1); %[output:9ba11935]

%Add title and labels
title('Plot of y1, x'); %[output:9ba11935]
xlabel('x'); %[output:9ba11935]
ylabel('y1'); %[output:9ba11935]
%Add some text to the plot
gtext('random text'); % Add text to the plot %[output:9ba11935]
%%
y2 = sin(x);

% Plot with different color and markers
figure(2) %[output:79623b31]
plot(x, y2, 'r--o'); % Red dashed line with circle markers %[output:79623b31]
title('Plot of y2=sin(x)'); %[output:79623b31]
xlabel('x'); %[output:79623b31]
ylabel('y2'); %[output:79623b31]

% Add legends
legend('sin(x) with markers'); %[output:79623b31]
%%
%[text] ## Histogram
% Create a histogram with specified number of bins
figure(3); %[output:0afc04df]
histogram(y2, 4); %[output:0afc04df]
title('Histogram of y2'); %[output:0afc04df]
xlabel('y2'); %[output:0afc04df]
ylabel('Frequency'); %[output:0afc04df]

% Create a histogram with specified number of bins
figure(4); %[output:7ce50222]
histogram(y2, 6); %[output:7ce50222]
title('Histogram of y2 with 6 Bins'); %[output:7ce50222]
xlabel('y2'); %[output:7ce50222]
ylabel('Frequency'); %[output:7ce50222]
%%
%[text] ## Display a menu
% capture user input
userInput = menu('Please choose one of the following food:', 'Burger', 'Pizza', 'Sushi');
% Switch case to handle user input
switch userInput %[output:group:809a80fd]
    case 1
        disp('You chose Burger.');
    case 2
        disp('You chose Pizza.');
    case 3
        disp('You chose Sushi.'); %[output:230f9bf7]
    otherwise
        disp('Invalid choice.');
end %[output:group:809a80fd]
%%
%[text] ## Nested menu for histogram bins
figure(5); %[output:3834c020]
userInput = menu('Please choose how many bins to plot y2:', '6 Bins', '9 Bins', '12 Bins');
switch userInput %[output:group:4c3270ee]
    case 1
        histogram(y2, 6);
    case 2
        histogram(y2, 9);
    case 3
        histogram(y2, 12); %[output:3834c020]
    otherwise
        disp('Invalid choice.');
end %[output:group:4c3270ee]

